mapper.select:
SELECT m.id, m.user_id, m.linked_bank_account_id, m.maturity_date, m.stock_code, m.market,
       m.currency, m.buy_amount, m.status, m.order_id, m.fail_reason, m.executed_at,
       m.created_at, m.updated_at, s.stock_name
FROM maturity_buy_reservations m
LEFT JOIN tradable_stocks s ON s.stock_code = m.stock_code
WHERE m.user_id = #{userId}
  AND m.linked_bank_account_id = #{linkedBankAccountId}
  AND m.stock_code = #{stockCode}
